  constructor(protected color: Color) {}
  abstract draw(): string;
}

class Circle extends Shape {
  draw() { return `Circle in ${this.color.fill()}`; }
}
```

**Типичная ошибка:** Думают, что Bridge и Adapter одинаковы, потому что оба используют композицию; Adapter о совместимости, Bridge о предотвращении хрупкости дизайна.

answer.en:
### Strategy Pattern: Pluggable Algorithms

Strategy encapsulates interchangeable algorithms behind a common interface. Use generic types and discriminated unions in TypeScript to maintain type safety while allowing runtime algorithm switching without conditional logic.

```typescript
interface PaymentStrategy {
  pay(amount: number): Promise<boolean>;
}

class CreditCardStrategy implements PaymentStrategy {
  async pay(amount: number) { return true; }
}

class PaymentProcessor {
  constructor(private strategy: PaymentStrategy) {}
  async process(amount: number) { return this.strategy.pay(amount); }
}
```

**Common interview trap:** Creating strategies without a common interface or using `any` type, defeating TypeScript's type safety benefits.

answer.ru:
### Паттерн Strategy: Подменяемые алгоритмы

Strategy инкапсулирует взаимозаменяемые алгоритмы за общим интерфейсом. Используйте дженерики и размеченные объединения в TypeScript для поддержания типобезопасности при переключении алгоритмов во время выполнения без условной логики.

```typescript
interface PaymentStrategy {
  pay(amount: number): Promise<boolean>;
}

class CreditCardStrategy implements PaymentStrategy {
  async pay(amount: number) { return true; }
}

class PaymentProcessor {
  constructor(private strategy: PaymentStrategy) {}
  async process(amount: number) { return this.strategy.pay(amount); }
}
```

**Типичная ошибка:** Создание стратегий без общего интерфейса или использование `any`, что лишает TypeScript преимуществ типобезопасности.

answer.en:
### Command Pattern: Encapsulated Actions

Command wraps requests as objects, enabling undo/redo by storing command history and re-executing or reversing them. Trade-off: storing all command objects consumes memory; optimize by implementing Memento pattern or using command compression strategies for high-frequency operations.

```typescript
interface Command { execute(): void; undo(): void; }

class IncrementCommand implements Command {
  constructor(private value: { num: number }, private amount = 1) {}
  execute() { this.value.num += this.amount; }
  undo() { this.value.num -= this.amount; }
}

class CommandHistory {
  private history: Command[] = [];
  executeCommand(cmd: Command) { cmd.execute(); this.history.push(cmd); }
  undo() { this.history.pop()?.undo(); }
}
```

**Common interview trap:** Not implementing undo properly or assuming unlimited memory for command history without considering application scale.

answer.ru:
### Паттерн Command: Инкапсулированные действия

Command оборачивает запросы как объекты, обеспечивая отката/повтор путем хранения истории команд и их повторного выполнения или отмены. Компромисс: хранение всех объектов команд потребляет память; оптимизируйте, реализуя паттерн Memento или используя стратегии сжатия команд для высокочастотных операций.

```typescript
interface Command { execute(): void; undo(): void; }

class IncrementCommand implements Command {
  constructor(private value: { num: number }, private amount = 1) {}
  execute() { this.value.num += this.amount; }
  undo() { this.value.num -= this.amount; }
}

class CommandHistory {
  private history: Command[] = [];
  executeCommand(cmd: Command) { cmd.execute(); this.history.push(cmd); }
  undo() { this.history.pop()?.undo(); }
}
```

**Типичная ошибка:** Неправильная реализация undo или предположение о неограниченной памяти для истории команд без учета масштаба приложения.

answer.en:
### Adapter Pattern for Interface Compatibility

Adapter converts one interface to another expected by clients, allowing incompatible classes to work together. Use it when you can't modify existing code but need integration.

```typescript
interface OldAPI { getData(): string; }
class NewAPI { fetchData(): Promise<string> { return Promise.resolve('data'); } }

class APIAdapter implements OldAPI {
  constructor(private newAPI: NewAPI) {}
  getData(): string { return 'sync-wrapped'; }
}
```

**Common interview trap:** Confusing Adapter with Decorator—Adapter changes interfaces, Decorator adds behavior.

answer.ru:
### Паттерн Adapter для совместимости интерфейсов

Adapter преобразует один интерфейс в другой, ожидаемый клиентами, позволяя несовместимым классам работать вместе. Используйте его, когда вы не можете изменить существующий код, но нужна интеграция.

```typescript
interface OldAPI { getData(): string; }
class NewAPI { fetchData(): Promise<string> { return Promise.resolve('data'); } }

class APIAdapter implements OldAPI {
  constructor(private newAPI: NewAPI) {}
  getData(): string { return 'sync-wrapped'; }
}
```

**Типичная ошибка:** Путаница Adapter с Decorator—Adapter меняет интерфейсы, Decorator добавляет поведение.

answer.en:
### Bridge Pattern for Decoupling

Bridge separates abstraction from implementation into independent hierarchies, preventing class explosion. Changes to implementation don't affect the abstraction and vice versa.

```typescript
interface Device { on(): void; off(): void; }
class TV implements Device { on() { console.log('TV on'); } off() { console.log('TV off'); } }

class RemoteControl { constructor(private device: Device) {} pressOn() { this.device.on(); } }
const remote = new RemoteControl(new TV());
```

**Common interview trap:** Thinking Bridge is just injecting a dependency—it's about maintaining two separate hierarchies independently.

answer.ru:
### Паттерн Bridge для отделения

Bridge разделяет абстракцию и реализацию в независимые иерархии, предотвращая взрыв классов. Изменения в реализации не влияют на абстракцию и наоборот.

```typescript
interface Device { on(): void; off(): void; }
class TV implements Device { on() { console.log('TV on'); } off() { console.log('TV off'); } }

class RemoteControl { constructor(private device: Device) {} pressOn() { this.device.on(); } }
const remote = new RemoteControl(new TV());
```

**Типичная ошибка:** Думать, что Bridge—это просто внедрение зависимости—речь идет о поддержании двух отдельных иерархий независимо.

answer.en:
### Observer Pattern for Event Coupling

Observer establishes one-to-many relationships where subjects notify observers of state changes without tight coupling. Multiple observers react independently to notifications.

```typescript
class Subject {
  private observers: Observer[] = [];
  subscribe(obs: Observer) { this.observers.push(obs); }
  notify(data: string) { this.observers.forEach(o => o.update(data)); }
}
interface Observer { update(data: string): void; }
class ConcreteObserver implements Observer { update(data: string) { console.log(data); } }
```

**Common interview trap:** Memory leaks from unsubscribed observers—always implement unsubscribe and clean up listeners.

answer.ru:
### Паттерн Observer для слабой связи событий

Observer устанавливает отношения «один ко многим», где субъекты уведомляют наблюдателей об изменениях состояния без тесной связи. Несколько наблюдателей реагируют независимо на уведомления.

```typescript
class Subject {
  private observers: Observer[] = [];
  subscribe(obs: Observer) { this.observers.push(obs); }
  notify(data: string) { this.observers.forEach(o => o.update(data)); }
}
interface Observer { update(data: string): void; }
class ConcreteObserver implements Observer { update(data: string) { console.log(data); } }
```

**Типичная ошибка:** Утечки памяти из неподписанных наблюдателей—всегда реализуйте unsubscribe и очистку слушателей.

answer.en:
### Decorator Pattern for Dynamic Behavior

Decorator wraps objects to add behavior dynamically without altering their structure. It's more flexible than inheritance because you can combine decorators at runtime and avoid class explosion.

```typescript
interface Component { operation(): string; }
class ConcreteComponent implements Component { operation() { return 'Base'; } }
class Decorator implements Component {
  constructor(private component: Component) {}
  operation() { return this.component.operation() + ' + Extra'; }
}
const decorated = new Decorator(new ConcreteComponent());
```

**Common interview trap:** Using Decorator when simple inheritance would suffice—Decorator adds complexity; use it for multiple optional combinations.

answer.ru:
### Паттерн Decorator для динамического поведения

Decorator оборачивает объекты для добавления поведения динамически без изменения их структуры. Он более гибкий, чем наследование, потому что вы можете комбинировать декораторы во время выполнения и избежать взрыва классов.

```typescript
interface Component { operation(): string; }
class ConcreteComponent implements Component { operation() { return 'Base'; } }
class Decorator implements Component {
  constructor(private component: Component) {}
  operation() { return this.component.operation() + ' + Extra'; }
}
const decorated = new Decorator(new ConcreteComponent());
```

**Типичная ошибка:** Использование Decorator, когда простого наследования было бы достаточно—Decorator добавляет сложность; используйте его для множественных дополнительных комбинаций.

answer.en:
### Strategy Pattern for Runtime Algorithm Selection

Strategy encapsulates interchangeable algorithms into separate classes, allowing clients to choose at runtime. It eliminates conditional logic and makes testing individual algorithms independent.

```typescript
interface SortStrategy { sort(arr: number[]): number[]; }
class QuickSort implements SortStrategy { sort(arr: number[]) { return arr.sort((a, b) => a - b); } }
class BubbleSort implements SortStrategy { sort(arr: number[]) { return [...arr]; } }

class Sorter { constructor(private strategy: SortStrategy) {} execute(arr: number[]) { return this.strategy.sort(arr); } }
```

**Common interview trap:** Over-engineering with Strategy for single algorithm—use it only when you have multiple variants or frequent changes.

answer.ru:
### Паттерн Strategy для выбора алгоритма во время выполнения

Strategy инкапсулирует взаимозаменяемые алгоритмы в отдельные классы, позволяя клиентам выбирать во время выполнения. Он устраняет условную логику и делает тестирование отдельных алгоритмов независимым.

```typescript
interface SortStrategy { sort(arr: number[]): number[]; }
class QuickSort implements SortStrategy { sort(arr: number[]) { return arr.sort((a, b) => a - b); } }
class BubbleSort implements SortStrategy { sort(arr: number[]) { return [...arr]; } }

class Sorter { constructor(private strategy: SortStrategy) {} execute(arr: number[]) { return this.strategy.sort(arr); } }
```

**Типичная ошибка:** Переинжиниринг со Strategy для одного алгоритма—используйте его только при множественных вариантах или частых изменениях.

answer.en:
### Decorator + Adapter Pattern

Use Decorator to wrap the API client with cross-cutting concerns (logging, caching), and Adapter to normalize incompatible interfaces. Decorators stack independently without modifying the original class, while Adapter bridges interface gaps when integrating third-party clients.

```typescript
class LoggingDecorator {
  constructor(private client: ApiClient) {}
  async request(url: string) {
    console.log(`Requesting ${url}`);
    return this.client.request(url);
  }
}

class CachingDecorator {
  private cache = new Map();
  constructor(private decorated: LoggingDecorator) {}
  async request(url: string) {
    if (this.cache.has(url)) return this.cache.get(url);
    const result = await this.decorated.request(url);
    this.cache.set(url, result);
    return result;
  }
}
```

**Common interview trap:** Confusing Decorator with inheritance; decorators compose behavior dynamically at runtime, not compile time.

answer.ru:
### Паттерны Decorator + Adapter

Используйте Decorator для обёртывания API-клиента с перекрёстными требованиями (логирование, кеширование), и Adapter для нормализации несовместимых интерфейсов. Декораторы складываются независимо без изменения исходного класса, а Adapter связывает интерфейсы при интеграции сторонних клиентов.

```typescript
class LoggingDecorator {
  constructor(private client: ApiClient) {}
  async request(url: string) {
    console.log(`Requesting ${url}`);
    return this.client.request(url);
  }
}

class CachingDecorator {
  private cache = new Map();
  constructor(private decorated: LoggingDecorator) {}
  async request(url: string) {
    if (this.cache.has(url)) return this.cache.get(url);
    const result = await this.decorated.request(url);
    this.cache.set(url, result);
    return result;
  }
}
```

**Типичная ошибка:** Путаница между Decorator и наследованием; декораторы компонуют поведение динамически во время выполнения, а не во время компиляции.

answer.en:
### Composite + Strategy + Observer

Composite treats individual nodes and tree structures uniformly via a common interface. Strategy encapsulates rendering logic per node type. Observer notifies subscribers when state changes. This allows flexible, tree-like component hierarchies with pluggable rendering.

```typescript
interface Node {
  render(): string;
}

class Element implements Node {
  constructor(private strategy: RenderStrategy) {}
  render() { return this.strategy.render(this); }
}

class CompositeNode implements Node {
  children: Node[] = [];
  render() { return this.children.map(c => c.render()).join(''); }
}

interface RenderStrategy { render(node: Node): string; }
class HtmlStrategy implements RenderStrategy {
  render(node: Node) { return `<div>${node.render()}</div>`; }
}
```

**Common interview trap:** Forgetting that Composite requires identical interfaces for leaf and composite nodes; mixing concerns instead of separating rendering strategy.

answer.ru:
